import type { CardConfig } from "../contracts/types";

export type SavedConfigSwitchOptionHook = (options: string, config: CardConfig) => string;

export function normalizeSavedConfigSwitch(
  config: CardConfig,
  normalizeOptions: SavedConfigSwitchOptionHook,
): boolean {
  if (config.type !== "") return false;
    if (!config.icon) config.icon = "Auto";
    if (!config.icon_on) config.icon_on = "Auto";
    config.type = "";
  config.options = normalizeOptions(config.options || "", config);
  return true;
}
